In validate-source Edge Function, implement Check 1:

async function checkReachability(url: string): Promise<{ reachable: boolean; reason?: string }> {
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 10000); // 10s timeout

    const response = await fetch(url, {
      method: 'HEAD',
      signal: controller.signal,
      headers: { 'User-Agent': 'NFL Wire Bot/1.0' }
    });
    clearTimeout(timeoutId);

    if (!response.ok) return { reachable: false, reason: `HTTP ${response.status}` };

    // Check content type is HTML or RSS/XML
    const contentType = response.headers.get('content-type');
    if (!contentType?.includes('html') && !contentType?.includes('xml') && !contentType?.includes('rss')) {
      return { reachable: false, reason: 'Invalid content type' };
    }

    return { reachable: true };
  } catch (error) {
    if (error.name === 'AbortError') return { reachable: false, reason: 'Timeout after 10s' };
    return { reachable: false, reason: error.message };
  }
}

