In validate-source Edge Function, implement Check 2:

async function checkTeamRelevance(url: string, teamName: string): Promise<{ relevant: boolean; confidence: number; reason?: string }> {
  // Fetch full content
  const response = await fetch(url);
  const html = await response.text();

  // Extract text content (remove HTML tags, scripts, styles)
  const textContent = html.replace(/<script[^>]*>.*?<\/script>/gi, '')
    .replace(/<style[^>]*>.*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 4000); // Limit to 4000 chars for API

  // Call Claude API
  const prompt = `Analyze if the following content contains news specifically about the ${teamName} NFL team. Consider mentions of team name, players, coaches, games, transactions. Reply with JSON only: { "relevant": true/false, "confidence": 0-100 }\n\nContent: ${textContent}`;

  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': Deno.env.get('ANTHROPIC_API_KEY'),
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify({
      model: 'claude-3-haiku-20240307',
      max_tokens: 200,
      messages: [{ role: 'user', content: prompt }]
    })
  });

  const result = await response.json();
  const parsed = JSON.parse(result.content[0].text);

  // Detect non-English (basic check)
  const englishRatio = (textContent.match(/[a-zA-Z]/g) || []).length / textContent.length;
  if (englishRatio < 0.7) {
    return { relevant: false, confidence: 0, reason: 'Non-English content detected' };
  }

  return { relevant: parsed.confidence >= 60, confidence: parsed.confidence };
}

Update source status: confidence >= 60 → 'approved', < 60 → 'flagged', non-English → 'flagged'.

