  if (!reachResult.reachable) {
    await supabase.from('sources')
      .update({ status: 'rejected', relevance_score: 0 })
      .eq('id', source_id);
    return new Response(JSON.stringify({ status: 'rejected', reason: reachResult.reason }));
  }

  // Run Check 2: Team Relevance (only if team-specific or user-submitted)
  if (source.team_id) {
    const relevanceResult = await checkTeamRelevance(source.url, source.teams.name);

    const finalStatus = relevanceResult.relevant ? 'approved' : 'flagged';
    await supabase.from('sources')
      .update({ 
        status: finalStatus, 
        relevance_score: relevanceResult.confidence 
      })
      .eq('id', source_id);

    // Send admin notification if flagged
    if (finalStatus === 'flagged') {
      await notifyAdmin(source, relevanceResult);
    }

    return new Response(JSON.stringify({ status: finalStatus, confidence: relevanceResult.confidence }));
  }

  // Global sources auto-approved
  await supabase.from('sources').update({ status: 'approved', relevance_score: 100 }).eq('id', source_id);
  return new Response(JSON.stringify({ status: 'approved' }));
});

