function rankAndSelectArticles(articles: Article[]): { leadStory: Article, quickHits: Article[], injuries: Article[] } {
  // Category priority: transaction > injury > game_analysis > rumor > general
  const categoryPriority = {
    'transaction': 5,
    'injury': 4,
    'game_analysis': 3,
    'rumor': 2,
    'general': 1
  };

  // Sort by category priority, then by published_at (newest first)
  const sorted = articles.sort((a, b) => {
    const priorityDiff = categoryPriority[b.category] - categoryPriority[a.category];
    if (priorityDiff !== 0) return priorityDiff;
    return new Date(b.published_at).getTime() - new Date(a.published_at).getTime();
  });

  // Select lead story (highest priority, not injury)
  const leadStory = sorted.find(a => a.category !== 'injury');

  // Select 3 quick hits (exclude lead story and injuries)
  const quickHits = sorted
    .filter(a => a.id !== leadStory.id && a.category !== 'injury')
    .slice(0, 3);

  // Select all injury articles
  const injuries = articles.filter(a => a.category === 'injury');

  return { leadStory, quickHits, injuries };
}

