Deno.serve(async (req) => {
  // Get all active teams
  const { data: teams } = await supabase
    .from('teams')
    .select('*')
    .eq('is_active', true);

  const results = [];

  for (const team of teams) {
    try {
      console.log(`Starting pipeline for ${team.name}`);

      // Run full pipeline
      const articles = await fetchArticles(team.id);
      const filtered = await filterArticlesByTeam(articles, team.name);
      const summarized = await summarizeArticles(filtered, team.name);
      const selected = rankAndSelectArticles(summarized);
      const stat = await generateStatOfTheDay(team.name, summarized);

      // Store in database for newsletter assembly
      const { data: insertedArticles } = await supabase
        .from('articles')
        .insert(summarized)
        .select();

      results.push({
        team_id: team.id,
        status: 'success',
        article_count: summarized.length,
        selected_articles: selected,
        stat_of_day: stat
      });

      console.log(`Completed pipeline for ${team.name}: ${summarized.length} articles`);
    } catch (error) {
      console.error(`Pipeline failed for ${team.name}:`, error);
      results.push({
        team_id: team.id,
        status: 'failed',
        error: error.message
      });
      // Continue with next team - failure does not block others
    }
  }

  return new Response(JSON.stringify({ results }));
});

