async function sendNewsletter(newsletter: Newsletter, teamId: string): Promise<void> {
  // Get all active subscribers for this team
  const { data: subscribers } = await supabase
    .from('subscribers')
    .select('*')
    .eq('team_id', teamId)
    .eq('is_active', true);

  console.log(`Sending to ${subscribers.length} subscribers`);

  // Send in batches (Resend limits to 100/second)
  const batchSize = 50;
  for (let i = 0; i < subscribers.length; i += batchSize) {
    const batch = subscribers.slice(i, i + batchSize);

    const sendPromises = batch.map(async (subscriber) => {
      // Render personalized email (with subscriber-specific tracking)
      const personalizedHtml = newsletter.html_content
        .replace('{{subscriber_id}}', subscriber.id)
        .replace('{{newsletter_id}}', newsletter.id);

      try {
        const response = await fetch('https://api.resend.com/emails', {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${Deno.env.get('RESEND_API_KEY')}`,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            from: 'NFL Wire <news@nflwire.com>',
            to: subscriber.email,
            subject: newsletter.subject_line,
            html: personalizedHtml
          })
        });

        if (!response.ok) {
          throw new Error(`Resend API error: ${response.status}`);
        }

        // Create newsletter_metrics record
        await supabase.from('newsletter_metrics').insert({
          newsletter_id: newsletter.id,
          subscriber_id: subscriber.id
        });
      } catch (error) {
        console.error(`Failed to send to ${subscriber.email}:`, error);
        // Continue with other subscribers
      }
    });

    await Promise.all(sendPromises);

    // Rate limiting delay between batches
    if (i + batchSize < subscribers.length) {
      await new Promise(resolve => setTimeout(resolve, 1000));
    }
  }

  // Update newsletter status
  await supabase
    .from('newsletters')
    .update({ 
      status: 'sent', 
      sent_at: new Date().toISOString() 
    })
    .eq('id', newsletter.id);
}

