### Step 1: Fetch Previously Published Article URLs

Query the `newsletters` table (and optionally a dedicated `published_articles` junction table if it exists) to collect all article URLs that have already appeared in sent newsletters for the given team:

```typescript
async function fetchPublishedArticleURLs(teamId: string): Promise<Set<string>> {
  // Query newsletters sent in the last N days (e.g., 30 days) to avoid unbounded growth
  const cutoff = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();

  const { data: newsletters, error } = await supabase
    .from('newsletters')
    .select('article_urls') // JSON array column storing URLs of included articles
    .eq('team_id', teamId)
    .eq('status', 'sent')
    .gte('sent_at', cutoff);

  if (error) throw error;

  const publishedURLs = new Set<string>();
  for (const newsletter of newsletters ?? []) {
    for (const url of newsletter.article_urls ?? []) {
      publishedURLs.add(url);
    }
  }
  return publishedURLs;
}
```

> **Note:** If `newsletters` does not yet store `article_urls` as a JSON column, add a migration to add `article_urls jsonb DEFAULT '[]'` to the `newsletters` table and populate it during newsletter assembly (Task 26).

