### Step 3: Semantic Title Similarity (>80%) Deduplication

Use a lightweight string similarity algorithm (e.g., Jaro-Winkler or normalized Levenshtein) to detect near-duplicate titles without requiring an external API call. For higher accuracy, optionally call the Claude or OpenAI embeddings API, but prefer a local approach for latency/cost reasons.

```typescript
function normalizeTitle(title: string): string {
  return title.toLowerCase().replace(/[^a-z0-9\s]/g, '').replace(/\s+/g, ' ').trim();
}

// Bigram-based Dice coefficient — fast and effective for short strings
function diceCoefficient(a: string, b: string): number {
  const bigrams = (s: string) => {
    const set = new Map<string, number>();
    for (let i = 0; i < s.length - 1; i++) {
      const bg = s.slice(i, i + 2);
      set.set(bg, (set.get(bg) ?? 0) + 1);
    }
    return set;
  };
  const aBigrams = bigrams(a);
  const bBigrams = bigrams(b);
  let intersection = 0;
  for (const [bg, count] of aBigrams) {
    intersection += Math.min(count, bBigrams.get(bg) ?? 0);
  }
  const total = (a.length - 1) + (b.length - 1);
  return total === 0 ? 1 : (2 * intersection) / total;
}

function isSimilarTitle(titleA: string, titleB: string, threshold = 0.80): boolean {
  return diceCoefficient(normalizeTitle(titleA), normalizeTitle(titleB)) >= threshold;
}
```

Also exclude articles whose titles are semantically similar to any previously published article title. Collect published titles from the same newsletter query above:

```typescript
async function fetchPublishedArticleTitles(teamId: string): Promise<string[]> {
  const cutoff = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
  const { data: newsletters } = await supabase
    .from('newsletters')
    .select('article_titles') // JSON array of title strings
    .eq('team_id', teamId)
    .eq('status', 'sent')
    .gte('sent_at', cutoff);
  return (newsletters ?? []).flatMap(n => n.article_titles ?? []);
}

function excludePublishedBySimilarTitle(
  articles: Article[],
  publishedTitles: string[],
  threshold = 0.80
): Article[] {
  return articles.filter(article =>
    !publishedTitles.some(pt => isSimilarTitle(article.title, pt, threshold))
  );
}
```

---

### Step 4: Collapse Same-Event Stories (Cross-Source Deduplication)

Among the remaining candidate articles, group articles that cover the same event (similar title ≥ 80%) and keep only the one with the highest `composite_score`:

```typescript
function collapseDuplicates(articles: Article[], threshold = 0.80): Article[] {
  const kept: Article[] = [];
  const consumed = new Set<string>();

  // Sort descending by composite_score so the best article is processed first
  const sorted = [...articles].sort((a, b) => b.composite_score - a.composite_score);

  for (const article of sorted) {
    if (consumed.has(article.url)) continue;

    // Mark all similar articles as consumed
    for (const other of sorted) {
      if (other.url === article.url || consumed.has(other.url)) continue;
      if (
        other.url === article.url || // exact URL match (safety)
        isSimilarTitle(article.title, other.title, threshold)
      ) {
        consumed.add(other.url);
      }
    }

    kept.push(article);
    consumed.add(article.url);
  }

  return kept;
}
```

