```ts
import { SCORE_WEIGHTS } from './pipeline-constants.ts';

export interface DimensionScores {
  relevance:    number; // 0–100
  significance: number; // 0–100
  credibility:  number; // 0–100
  uniqueness:   number; // 0–100
}

export interface ScoredArticle {
  id: string;
  score_relevance:    number;
  score_significance: number;
  score_credibility:  number;
  score_uniqueness:   number;
  composite_score:    number;
}

/**
 * Computes the canonical weighted composite score.
 * All inputs are expected on a 0–100 scale.
 * Returns a value on a 0–100 scale.
 */
export function computeCompositeScore(dims: DimensionScores): number {
  return (
    dims.relevance    * SCORE_WEIGHTS.relevance    +
    dims.significance * SCORE_WEIGHTS.significance +
    dims.credibility  * SCORE_WEIGHTS.credibility  +
    dims.uniqueness   * SCORE_WEIGHTS.uniqueness
  );
}

/**
 * Determines the active threshold based on candidate article count.
 */
export function resolveThreshold(candidateCount: number): number {
  return candidateCount < LOW_VOLUME_ARTICLE_COUNT
    ? COMPOSITE_SCORE_THRESHOLD_LOW_VOLUME
    : COMPOSITE_SCORE_THRESHOLD_STANDARD;
}
```

