## Step 2: Game Schedule Lookup Utility

Create `supabase/functions/_shared/game-schedule.ts`:

```typescript
export interface GameWindow {
  gameId: string;
  teamId: string;
  scheduledStart: Date;
  scheduledEnd: Date;   // scheduledStart + 3.5 hours (typical NFL game)
}

/**
 * Returns the active game window for a team at a given moment, or null if no game is in progress.
 * Queries a `game_schedule` table (or external NFL schedule API) for games where
 * scheduledStart <= now <= scheduledEnd + 30min buffer.
 */
export async function getActiveGameWindow(
  supabase: SupabaseClient,
  teamId: string,
  atTime: Date = new Date()
): Promise<GameWindow | null> {
  const bufferMs = 30 * 60 * 1000; // 30-min post-game buffer
  const { data: games } = await supabase
    .from('game_schedule')
    .select('*')
    .eq('team_id', teamId)
    .lte('scheduled_start', atTime.toISOString())
    .gte('scheduled_end', new Date(atTime.getTime() - bufferMs).toISOString())
    .limit(1)
    .single();

  if (!games) return null;
  return {
    gameId: games.id,
    teamId: games.team_id,
    scheduledStart: new Date(games.scheduled_start),
    scheduledEnd: new Date(games.scheduled_end),
  };
}
```

> **Note:** If a `game_schedule` table does not yet exist, create it with columns: `id`, `team_id`, `scheduled_start`, `scheduled_end`, `opponent`, `home_away`. Seed it from an NFL schedule API or manually.

