## Step 3: Mid-Game Keyword Detection

Create `supabase/functions/_shared/midgame-detector.ts`:

```typescript
const MID_GAME_KEYWORDS = [
  'live', 'in progress', 'in-progress', 'halftime', 'half time',
  'q1', 'q2', 'q3', 'q4', 'first quarter', 'second quarter',
  'third quarter', 'fourth quarter', 'overtime', 'ot',
  'score update', 'live update', 'live blog', 'game thread',
  'breaking', 'just in', 'developing',
];

export interface MidGameFlagResult {
  isMidGame: boolean;
  matchedKeywords: string[];
  reason: string;
}

export function detectMidGameArticle(
  article: { title: string; description?: string; published_at: string },
  gameWindow: GameWindow | null
): MidGameFlagResult {
  if (!gameWindow) {
    return { isMidGame: false, matchedKeywords: [], reason: 'No active game window' };
  }

  const articleTime = new Date(article.published_at);
  const isWithinGameWindow =
    articleTime >= gameWindow.scheduledStart &&
    articleTime <= new Date(gameWindow.scheduledEnd.getTime() + 30 * 60 * 1000);

  if (!isWithinGameWindow) {
    return { isMidGame: false, matchedKeywords: [], reason: 'Article outside game window' };
  }

  const searchText = `${article.title} ${article.description ?? ''}`.toLowerCase();
  const matched = MID_GAME_KEYWORDS.filter(kw => searchText.includes(kw));

  if (matched.length > 0) {
    return {
      isMidGame: true,
      matchedKeywords: matched,
      reason: `Article published during game window and contains keywords: ${matched.join(', ')}`,
    };
  }

  // Even without keywords, if published strictly during game window, flag it
  return {
    isMidGame: true,
    matchedKeywords: [],
    reason: 'Article published during active game window (timestamp match)',
  };
}
```

