## Step 2: Paywall Indicator Detection

Define a list of known paywall and sign-in prompt patterns (case-insensitive regex or substring match against the extracted text and/or raw HTML):

```typescript
const PAYWALL_PATTERNS = [
  /subscribe to (continue|read|access)/i,
  /sign in to (continue|read|access|view)/i,
  /log in to (continue|read|access|view)/i,
  /this (article|content|story) is (for|available to) (subscribers|members)/i,
  /create a free account to (read|continue|access)/i,
  /you('ve| have) reached your (free article|monthly) limit/i,
  /unlock (this|full) (article|story|content)/i,
  /premium (content|article|story)/i,
  /already a subscriber\?/i,
  /get unlimited access/i,
];

const BOILERPLATE_PATTERNS = [
  /we use cookies to/i,
  /by (clicking|continuing|using this site) you agree to our (cookie|privacy)/i,
  /cookie (policy|consent|settings)/i,
  /accept all cookies/i,
  /manage cookie preferences/i,
];

function detectPaywall(text: string): boolean {
  return PAYWALL_PATTERNS.some(pattern => pattern.test(text));
}

function detectBoilerplate(text: string): boolean {
  return BOILERPLATE_PATTERNS.some(pattern => pattern.test(text));
}
```

Apply both checks to the extracted body text (and optionally the raw HTML before stripping):

```typescript
const isPaywalled = detectPaywall(extractedBody) || detectPaywall(rawHtml);
const isBoilerplate = detectBoilerplate(extractedBody);

if (isPaywalled || isBoilerplate) {
  const reason = isPaywalled ? 'paywall_detected' : 'boilerplate_detected';
  logFetchQuality(sourceId, articleUrl, reason, null);
  incrementPaywallCount(sourceId);
  continue; // Discard article
}
```

