## Step 4: Per-Source Paywall Rate Tracking

After each pipeline run, compute the paywall rate per source and update the `sources` table:

```typescript
async function updateSourcePaywallRate(sourceId: string): Promise<void> {
  // Count total fetch attempts for this source in last 30 days
  const since = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();

  const { count: totalAttempts } = await supabase
    .from('fetch_quality_logs')
    .select('*', { count: 'exact', head: true })
    .eq('source_id', sourceId)
    .gte('created_at', since);

  const { count: paywallHits } = await supabase
    .from('fetch_quality_logs')
    .select('*', { count: 'exact', head: true })
    .eq('source_id', sourceId)
    .in('discard_reason', ['paywall_detected', 'boilerplate_detected'])
    .gte('created_at', since);

  const paywallRate = totalAttempts > 0 ? paywallHits / totalAttempts : 0;

  await supabase
    .from('sources')
    .update({
      paywall_rate: paywallRate,
      status: paywallRate > 0.3 ? 'flagged' : undefined, // only downgrade, never auto-approve
    })
    .eq('id', sourceId);

  if (paywallRate > 0.3) {
    await notifyAdmin({
      type: 'source_flagged',
      data: {
        url: sourceUrl,
        reason: `Paywall rate exceeded 30% (${Math.round(paywallRate * 100)}%)`,
        source_id: sourceId,
      },
    });
  }
}
```

