async function isSummaryGeneric(
  summary: string,
  teamName: string,
  articleDate: string
): Promise<{ isGeneric: boolean; reason: string }> {
  const prompt = `You are a quality checker for NFL newsletter summaries.

Evaluate the following summary and determine if it contains GENERIC language that could apply to ANY NFL team or ANY week — language that lacks specificity to the team, players, events, or date context.

Team: ${teamName}
Article Date: ${articleDate}
Summary: "${summary}"

Generic language examples to flag:
- "The team is preparing for their upcoming game"
- "Players are working hard in practice"
- "The coaching staff is focused on improvement"
- "Fans are excited about the season"
- "The team faces challenges ahead"

A summary is SPECIFIC if it mentions:
- Named players (e.g., "Geno Smith", "DK Metcalf")
- Specific game opponents, scores, or dates
- Concrete stats or injury details
- Specific plays, schemes, or transactions

Reply with JSON only:
{
  "is_generic": true | false,
  "reason": "brief explanation"
}`;

  const response = await anthropic.messages.create({
    model: 'claude-3-haiku-20240307',
    max_tokens: 200,
    messages: [{ role: 'user', content: prompt }],
  });

  const text = response.content[0].type === 'text' ? response.content[0].text : '{}';
  const parsed = JSON.parse(text.trim());
  return { isGeneric: parsed.is_generic ?? false, reason: parsed.reason ?? '' };
}
