## Step 4: Integrate into `summarizeArticles` Pipeline

Modify the existing `summarizeArticles` function to call the freshness check after each summary is generated:

```typescript
async function summarizeArticles(articles: Article[], teamName: string): Promise<Article[]> {
  const summarized = [];

  for (const article of articles) {
    try {
      // --- Existing summarization logic (Task 18) ---
      let summary = await generateInitialSummary(article, teamName);
      let category = article.category;
      let isGeneric = false;

      // --- NEW: Freshness check ---
      const articleDate = article.published_at
        ? new Date(article.published_at).toISOString().split('T')[0]
        : new Date().toISOString().split('T')[0];

      const { isGeneric: flagged, reason } = await isSummaryGeneric(summary, teamName, articleDate);

      if (flagged) {
        console.warn(`Generic summary detected for article ${article.id}: ${reason}. Regenerating...`);
        summary = await regenerateSpecificSummary(article, teamName, articleDate);
        isGeneric = true; // Mark as was-generic even after regeneration for tracking
      }

      // --- Update article in DB ---
      await supabase
        .from('articles')
        .update({
          summary,
          category,
          is_generic_summary: isGeneric,
        })
        .eq('id', article.id);

      summarized.push({ ...article, summary, category, is_generic_summary: isGeneric });
    } catch (err) {
      console.error(`Failed to summarize article ${article.id}:`, err);
      summarized.push(article);
    }
  }

  return summarized;
}
```

