async function checkSummaryContradiction(
  headline: string,
  summary: string,
  claudeApiKey: string
): Promise<{ contradicts: boolean; reason: string }> {
  const prompt = `You are a fact-checking assistant. Your job is to determine whether a news summary contradicts or misrepresents its own headline.

Headline: "${headline}"
Summary: "${summary}"

Does the summary contradict or materially misrepresent the headline? Consider:
- Factual contradictions (e.g., headline says player is OUT, summary says player is IN)
- Sentiment inversions (e.g., headline is positive, summary is negative about the same event)
- Subject mismatches (e.g., headline is about one player, summary focuses on a different player in a contradictory way)

Reply with JSON only, no markdown:
{
  "contradicts": true | false,
  "reason": "brief explanation"
}`;

  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'x-api-key': claudeApiKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json',
    },
    body: JSON.stringify({
      model: 'claude-3-haiku-20240307',
      max_tokens: 256,
      messages: [{ role: 'user', content: prompt }],
    }),
  });

  const data = await response.json();
  const text = data.content?.[0]?.text ?? '{"contradicts": false, "reason": "parse error"}';

  try {
    return JSON.parse(text);
  } catch {
    return { contradicts: false, reason: 'Failed to parse contradiction check response' };
