## Step 3: Integrate Contradiction Check into `summarizeArticles`

Modify the existing `summarizeArticles` function (Task 18) to call the contradiction check after each summary is generated. Allow up to **2 regeneration attempts** before giving up and flagging the article:

```typescript
const MAX_REGENERATION_ATTEMPTS = 2;

async function summarizeArticles(articles: Article[], teamName: string): Promise<Article[]> {
  const claudeApiKey = Deno.env.get('ANTHROPIC_API_KEY')!;
  const summarized = [];

  for (const article of articles) {
    try {
      let summary = '';
      let category = '';
      let contradicts = false;
      let attempt = 0;

      while (attempt <= MAX_REGENERATION_ATTEMPTS) {
        // --- existing summarization call ---
        const result = await generateSummary(article, teamName, claudeApiKey);
        summary = result.summary;
        category = result.category;

        // --- new contradiction check ---
        const check = await checkSummaryContradiction(article.title, summary, claudeApiKey);
        contradicts = check.contradicts;

        if (!contradicts) break;

        console.warn(
          `[contradiction] Attempt ${attempt + 1}: summary contradicts headline for article ${article.id}. Reason: ${check.reason}`
        );
        attempt++;
      }

      // Persist result — if still contradicting after max attempts, flag it and skip publishing
      const { error } = await supabase
        .from('articles')
        .update({
          summary,
          category,
          contradicts_headline: contradicts,
        })
        .eq('id', article.id);

      if (error) throw error;

      if (!contradicts) {
        summarized.push({ ...article, summary, category, contradicts_headline: false });
      } else {
        console.error(
          `[contradiction] Article ${article.id} flagged as contradicts_headline=true after ${MAX_REGENERATION_ATTEMPTS} attempts. Excluding from newsletter.`
        );
        // Do NOT push to summarized — article will not be published
      }
    } catch (err) {
      console.error(`Failed to summarize article ${article.id}:`, err);
    }
  }

  return summarized;
}
```

