## Step 3: Implement `detectSpeculativeLanguage(summary: string, originalContent: string): { flagged: boolean; offendingWords: string[] }`

```typescript
const SPECULATIVE_WORDS = ['may', 'could', 'might'];

export function detectSpeculativeLanguage(
  summary: string,
  originalContent: string
): { flagged: boolean; offendingWords: string[] } {
  const summaryLower = summary.toLowerCase();
  const originalLower = originalContent.toLowerCase();

  const offendingWords: string[] = [];

  for (const word of SPECULATIVE_WORDS) {
    // Match whole-word occurrences in the summary
    const wordRegex = new RegExp(`\\b${word}\\b`, 'gi');
    const inSummary = wordRegex.test(summaryLower);

    if (inSummary) {
      // Check if the word also appears in the original article
      const inOriginal = new RegExp(`\\b${word}\\b`, 'gi').test(originalLower);
      if (!inOriginal) {
        offendingWords.push(word);
      }
    }
  }

  return { flagged: offendingWords.length > 0, offendingWords };
}
```

