## Step 4: Integrate into `summarizeArticles` Pipeline

Within the existing `summarizeArticles` function, after receiving the Claude-generated summary:

```typescript
async function summarizeArticles(articles: Article[], teamName: string): Promise<Article[]> {
  const summarized = [];

  for (const article of articles) {
    let summary = await callClaudeForSummary(article, teamName); // existing logic
    let summaryVersion = article.summary_version ?? 1;
    let regenerated = false;

    // Step A: Enforce sentence limit
    summary = enforceSentenceLimit(summary, 3);

    // Step B: Detect speculative language
    const { flagged, offendingWords } = detectSpeculativeLanguage(summary, article.raw_content);

    if (flagged) {
      // Regenerate with explicit instruction to avoid speculative language
      const regenerationPrompt = `Rewrite the following summary without using speculative language (do not use: ${offendingWords.join(', ')}). Keep it factual and within 3 sentences.\n\nSummary: ${summary}\n\nOriginal Article: ${article.raw_content.slice(0, 3000)}`;
      summary = await callClaudeRaw(regenerationPrompt);
      summary = enforceSentenceLimit(summary, 3); // Re-enforce after regeneration
      summaryVersion += 1;
      regenerated = true;
    }

    // Step C: If this is a re-run of an existing article, increment version
    if (article.summary && article.summary !== summary && !regenerated) {
      summaryVersion += 1;
    }

    summarized.push({
      ...article,
      summary,
      summary_version: summaryVersion,
      speculative_language_flagged: flagged, // optional diagnostic field
    });
  }

  return summarized;
}
```

