## Component 2: Weekly Admin Report (Lowest vs Highest Rated Newsletters)

### Create a new Edge Function: `supabase/functions/weekly-satisfaction-report/index.ts`

```typescript
Deno.serve(async () => {
  const oneWeekAgo = new Date();
  oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

  // Fetch all sent newsletters from the past week with metrics
  const { data: newsletters } = await supabase
    .from('newsletters')
    .select('id, team_id, sent_at, teams(name), newsletter_metrics(thumbs_up_count, thumbs_down_count, open_count)')
    .eq('status', 'sent')
    .gte('sent_at', oneWeekAgo.toISOString());

  // Compute satisfaction rate per newsletter
  const rated = (newsletters ?? []).map(n => {
    const metrics = n.newsletter_metrics?.[0] ?? {};
    const up = metrics.thumbs_up_count ?? 0;
    const down = metrics.thumbs_down_count ?? 0;
    const total = up + down;
    const rate = total > 0 ? (up / total) * 100 : null;
    return { ...n, thumbs_up: up, thumbs_down: down, total_feedback: total, satisfaction_rate: rate };
  }).filter(n => n.satisfaction_rate !== null);

  // Sort to find top 3 and bottom 3
  const sorted = [...rated].sort((a, b) => (b.satisfaction_rate ?? 0) - (a.satisfaction_rate ?? 0));
  const highest = sorted.slice(0, 3);
  const lowest = sorted.slice(-3).reverse();

  // Fetch article logs for lowest-rated newsletters
  const lowestIds = lowest.map(n => n.id);
  const { data: articleLogs } = await supabase
    .from('feedback_article_logs')
    .select('newsletter_id, articles')
    .in('newsletter_id', lowestIds);

  // Build HTML report comparing patterns
  const reportHtml = buildWeeklyReportHtml({ highest, lowest, articleLogs, weekStart: oneWeekAgo });

  // Send report via admin notification
  await notifyAdmin({
    type: 'weekly_satisfaction_report',
    data: { subject: `Weekly Satisfaction Report – ${new Date().toDateString()}`, html: reportHtml }
