## Component 3: Auto-Flag for Low Satisfaction (< 60% for 3 Consecutive Issues)

### Create a helper function `checkConsecutiveLowSatisfaction` in `_shared/satisfaction-check.ts`

```typescript
export async function checkConsecutiveLowSatisfaction(teamId: string): Promise<void> {
  // Fetch last 3 sent newsletters for this team
  const { data: recent } = await supabase
    .from('newsletters')
    .select('id, sent_at, newsletter_metrics(thumbs_up_count, thumbs_down_count)')
    .eq('team_id', teamId)
    .eq('status', 'sent')
    .order('sent_at', { ascending: false })
    .limit(3);

  if (!recent || recent.length < 3) return; // Not enough history

  const allBelowThreshold = recent.every(n => {
    const metrics = n.newsletter_metrics?.[0] ?? {};
    const up = metrics.thumbs_up_count ?? 0;
    const down = metrics.thumbs_down_count ?? 0;
    const total = up + down;
    if (total === 0) return false; // Skip if no feedback
    return (up / total) * 100 < 60;
  });

  if (allBelowThreshold) {
    // Check if we already flagged this recently (avoid duplicate alerts within 7 days)
    const { data: recentFlag } = await supabase
      .from('admin_flags')
      .select('id, created_at')
      .eq('team_id', teamId)
      .eq('flag_type', 'low_satisfaction_streak')
      .gte('created_at', new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString())
      .limit(1);

    if (recentFlag && recentFlag.length > 0) return; // Already flagged recently

    // Insert flag record
    await supabase.from('admin_flags').insert({
      team_id: teamId,
      flag_type: 'low_satisfaction_streak',
      details: {
        newsletter_ids: recent.map(n => n.id),
        satisfaction_rates: recent.map(n => {
          const m = n.newsletter_metrics?.[0] ?? {};
          const up = m.thumbs_up_count ?? 0;
          const down = m.thumbs_down_count ?? 0;
          const total = up + down;
          return total > 0 ? Math.round((up / total) * 100) : null;
        }),
      },
      resolved: false,
    });

    // Send admin notification
    await notifyAdmin({
      type: 'low_satisfaction_streak',
      data: {
        teamId,
        newsletterIds: recent.map(n => n.id),
        message: `Satisfaction rate has been below 60% for 3 consecutive issues for team ${teamId}. Manual review required.`,
      }
    });
  }
}
```

