## Step 1: Define NFL Calendar Phases

```typescript
export type NFLSeasonPhase =
  | 'preseason'
  | 'regular_season'
  | 'playoffs'
  | 'super_bowl_week'
  | 'offseason'
  | 'draft_period';

export interface SeasonalConfig {
  phase: NFLSeasonPhase;
  scoringWeightOverrides: Partial<ScoringWeights>;
  compositeThresholdOverride?: number;       // replaces default (e.g. 60)
  globalSourceFilterTightened: boolean;      // true = stricter source tier filter
  uniquenessMode: 'default' | 'spread';      // 'spread' forces coverage diversity
}
```

