## Step 3: Define Phase-Specific Scoring Adjustments

```typescript
export function getSeasonalConfig(phase: NFLSeasonPhase): SeasonalConfig {
  const base: SeasonalConfig = {
    phase,
    scoringWeightOverrides: {},
    compositeThresholdOverride: undefined,
    globalSourceFilterTightened: false,
    uniquenessMode: 'default',
  };

  switch (phase) {
    case 'offseason':
      return {
        ...base,
        scoringWeightOverrides: {
          significance: 0.6,   // reduced from default (e.g. 1.0)
          rumor: 1.5,          // elevated: rumors are more newsworthy in offseason
        },
      };

    case 'draft_period':
      return {
        ...base,
        compositeThresholdOverride: 55,  // lower bar: more draft content qualifies
        scoringWeightOverrides: {
          transaction: 1.8,    // elevated: trades, signings, picks are top priority
          rumor: 1.4,          // draft rumors are highly relevant
        },
      };

    case 'playoffs':
      return {
        ...base,
        globalSourceFilterTightened: true,  // only tier-1 sources pass
        scoringWeightOverrides: {
          game_analysis: 1.6,
          significance: 1.3,
        },
      };

    case 'super_bowl_week':
      return {
        ...base,
        globalSourceFilterTightened: true,
        uniquenessMode: 'spread',  // force diverse coverage angles
        scoringWeightOverrides: {
          game_analysis: 1.8,
          significance: 1.4,
        },
      };

    case 'preseason':
      return {
        ...base,
        scoringWeightOverrides: {
          transaction: 1.3,
          injury: 1.2,
        },
      };

    case 'regular_season':
    default:
      return base; // use all defaults
  }
}
```

