### Step 2: Dynamic Relevance Score Cutoff

Apply the base relevance threshold (e.g., 65) first to get a candidate pool. Then evaluate the count and adjust:

```typescript
const BASE_THRESHOLD = 65;
const STRICT_THRESHOLD = 75;
const LENIENT_THRESHOLD = 55;

async function applyDynamicThreshold(
  articles: Article[],
  teamId: string
): Promise<Article[]> {
  // Apply per-source cap first
  const capped = applyPerSourceCap(articles);

  // Apply base threshold
  let passing = capped.filter(a => a.composite_score >= BASE_THRESHOLD);

  if (passing.length > 10) {
    // Too many articles: apply stricter cutoff
    passing = capped.filter(a => a.composite_score >= STRICT_THRESHOLD);
  } else if (passing.length < 3) {
    // Too few articles: apply lenient cutoff and notify admin
    passing = capped.filter(a => a.composite_score >= LENIENT_THRESHOLD);
    await notifyAdmin({
      type: 'low_article_count',
      data: {
        team_id: teamId,
        count_at_base_threshold: passing.length,
        lenient_threshold: LENIENT_THRESHOLD,
        message: `Fewer than 3 articles passed the base threshold (${BASE_THRESHOLD}) for team ${teamId}. Lowered cutoff to ${LENIENT_THRESHOLD}.`
      }
    });
  }

  return passing;
}
```

