## Step 2: Refactor `generateStatOfTheDay`

Replace the existing implementation with a grounded version:

```typescript
interface StatOfTheDay {
  stat: string;
  context: string;
  source_article_id: string;
  validation_notes: string;
}

async function generateStatOfTheDay(
  teamName: string,
  articles: Article[]  // full article objects with id, title, content/summary
): Promise<StatOfTheDay | null> {
  if (!articles || articles.length === 0) return null;

  // Build a prompt that instructs Claude to extract a stat from the provided articles only
  const articlesPayload = articles.map((a, i) =>
    `[Article ${i + 1}] ID: ${a.id}\nTitle: ${a.title}\nContent: ${a.content ?? a.summary ?? ''}`
  ).join('\n\n');

  const prompt = `You are a sports newsletter editor. Your task is to find ONE specific, verifiable statistic about the ${teamName} NFL team that appears explicitly in the articles below. 

RULES:
- The stat MUST be directly stated or clearly implied by the article text. Do NOT invent or infer statistics not present in the articles.
- Return the Article ID of the source article.
- If no suitable verifiable statistic exists in any article, respond with JSON: { "found": false }

Articles:
${articlesPayload}

Respond ONLY with valid JSON in one of these two formats:
{ "found": true, "stat": "<the statistic sentence>", "context": "<1-2 sentence explanation>", "source_article_id": "<article UUID>" }
{ "found": false }`;

  const response = await anthropic.messages.create({
    model: 'claude-opus-4-5',
    max_tokens: 512,
    messages: [{ role: 'user', content: prompt }],
  });

  let parsed: any;
  try {
    parsed = JSON.parse(response.content[0].text.trim());
  } catch {
    return null;
  }

  if (!parsed.found) return null;

  // Validate that the returned source_article_id actually exists in our article set
  const sourceArticle = articles.find(a => a.id === parsed.source_article_id);
  if (!sourceArticle) return null;

  // Step 3: Optional web-search verification
  const validationNotes = await verifyStatWithWebSearch(parsed.stat, teamName);

  return {
    stat: parsed.stat,
    context: parsed.context,
    source_article_id: parsed.source_article_id,
    validation_notes: validationNotes,
  };
}
```

